  function readFilterPanel(container){
    return {
      schoolYear: container.querySelector('[name="schoolYear"]').value,
      productType: container.querySelector('[name="productType"]').value,
      contentArea: container.querySelector('[name="contentArea"]').value,
      grade: container.querySelector('[name="grade"]').value,
      states: getSelectedValues(container.querySelector('[name="states"]')),
      demographic: container.querySelector('[name="demographic"]').value,
      size: container.querySelector('[name="size"]').value,
      lea: container.querySelector('[name="lea"]').value.trim(),
      nces: container.querySelector('[name="nces"]').value.trim(),
      productSearch: container.querySelector('[name="productSearch"]').value.trim(),
      sort: container.querySelector('[name="sort"]').value
    };
  }
  function bindFilterPanel(container, state, update){
    container.querySelectorAll('select,input').forEach(el => {
      const evt = el.tagName === "INPUT" ? "input" : "change";
      el.addEventListener(evt, () => {
        const next = clone(state);
        next.filters = readFilterPanel(container);
        update(next);
      });
    });
  }
  function parseQuery(query){
    const text = String(query || "").trim();
    const lower = text.toLowerCase();
    const parsed = {
      states: [],
      schoolYear: null,
      contentArea: null,
      grade: null,
      demographic: null,
      productType: null,
      size: null,
      sort: null,
      limit: null,
      productSearch: "",
      assumptions: [],
      summaryParts: []
    };

    const yearMatch = lower.match(/\b(20\d{2})\s*[-/]\s*(\d{2}|\d{4})\b/);
    if(yearMatch){
      const end = yearMatch[2].length === 2 ? yearMatch[2] : yearMatch[2].slice(2);
      parsed.schoolYear = `${yearMatch[1]}-${end}`;
      parsed.summaryParts.push(`school year ${parsed.schoolYear}`);
    }

    Object.entries(stateNameToAbbr).forEach(([stateName, abbr]) => {
      if(lower.includes(stateName)){
        parsed.states.push(stateAbbrToName[abbr]);
      }
    });
    Object.keys(stateAbbrToName).forEach(abbr => {
      const pattern = new RegExp(`\\b${abbr.toLowerCase()}\\b`);
      if(pattern.test(lower) && !parsed.states.includes(stateAbbrToName[abbr])){
        parsed.states.push(stateAbbrToName[abbr]);
      }
    });
    if(parsed.states.length){
      parsed.summaryParts.push(parsed.states.join(", "));
    }

    if(/\b(math|mathematics)\b/.test(lower)){
      parsed.contentArea = "Math";
      parsed.summaryParts.push("Math");
    } else if(/\b(ela|english language arts|reading|literacy)\b/.test(lower)){
      parsed.contentArea = "ELA";
      parsed.summaryParts.push("ELA");
    }

    const gradeRegex = lower.match(/\bgrade\s*(k|[1-9]|1[0-2])\b/);
    if(gradeRegex){
      parsed.grade = gradeRegex[1].toUpperCase();
      parsed.summaryParts.push(`grade ${parsed.grade}`);
    } else if(/\bkindergarten\b/.test(lower)){
      parsed.grade = "K";
      parsed.summaryParts.push("kindergarten");
    } else if(/\belementary\b/.test(lower)){
      parsed.grade = "3";
      parsed.assumptions.push("“Elementary” was centered on the K–5 band for current curriculum and change signals.");
    } else if(/\bmiddle school\b/.test(lower)){
      parsed.grade = "6";
      parsed.assumptions.push("“Middle school” was mapped to the 6–8 grade band.");
    } else if(/\bhigh school\b/.test(lower)){
      parsed.grade = "9";
      parsed.assumptions.push("“High school” was mapped to the 9–12 grade band.");
    }

    if(/\bhqim\b|high[-\s]?quality instructional materials/.test(lower)){
      parsed.productType = "HQIM";
      parsed.assumptions.push("“Districts with HQIM” was interpreted as districts with at least one HQIM product in the scoped subject/grade band.");
      parsed.summaryParts.push("HQIM");
    } else if(/\bsupplemental\b/.test(lower)){
      parsed.productType = "Supplemental";
      parsed.summaryParts.push("supplemental products");
    } else if(/\bcore\b/.test(lower)){
      parsed.productType = "Core";
      parsed.summaryParts.push("core products");
    }

    if(/\bmajority white\b/.test(lower)){
      parsed.demographic = "majorityWhite";
      parsed.assumptions.push("“Majority white” was operationalized as white enrollment of at least 50%.");
      parsed.summaryParts.push("majority white");
    } else if(/\bmajority black\b/.test(lower)){
      parsed.demographic = "majorityBlack";
      parsed.summaryParts.push("majority Black");
    } else if(/\bmajority hispanic\b/.test(lower) || /\bmajority latino\b/.test(lower)){
      parsed.demographic = "majorityHispanic";
      parsed.summaryParts.push("majority Hispanic");
    } else if(/\bmultilingual\b|\benglish learners?\b|\bel\b/.test(lower)){
      parsed.demographic = "multilingual";
      parsed.summaryParts.push("multilingual");
    }

    if(/\bsmall\b/.test(lower)){
      parsed.size = "Small";
      parsed.assumptions.push("“Small district” was operationalized as fewer than 5,000 students.");
      parsed.summaryParts.push("small districts");
    } else if(/\blarge\b/.test(lower)){
      parsed.size = "Large";
      parsed.assumptions.push("“Large district” was operationalized as more than 25,000 students.");
      parsed.summaryParts.push("large districts");
    }

    if(/\bmost multilingual learners\b|\bhighest multilingual\b/.test(lower)){
      parsed.sort = "multilingualDesc";
      parsed.assumptions.push("“Most multilingual learners” was ranked by multilingual learner count.");
    } else if(/\blikely to change\b|\bchange curriculum\b|\bchange materials\b/.test(lower)){
      parsed.sort = "changeDesc";
      parsed.assumptions.push("Change likelihood uses the selected subject and grade band when available.");
      parsed.summaryParts.push("ranked by change likelihood");
    } else if(/\blargest\b/.test(lower)){
      parsed.sort = "enrollmentDesc";
    }

    const topMatch = lower.match(/\btop\s+(\d+)\b/);
    if(topMatch){
      parsed.limit = Number(topMatch[1]);
    } else if(/\btop five\b/.test(lower)){
      parsed.limit = 5;
    }

    const knownProducts = [...new Set(data.districts.flatMap(d => [
      ...Object.values(d.current.Math).map(p => p.name),
      ...Object.values(d.current.ELA).map(p => p.name),
      d.supplemental.Math,
      d.supplemental.ELA
    ]))];
    const matchedProduct = knownProducts.find(name => lower.includes(name.toLowerCase()));
    if(matchedProduct){
      parsed.productSearch = matchedProduct;
      parsed.summaryParts.push(matchedProduct);
    }
    return parsed;
  }
  function applyParsedToState(parsed, appState){
    const next = clone(normalizeState(appState));
    if(parsed.schoolYear) next.filters.schoolYear = parsed.schoolYear;
    if(parsed.productType) next.filters.productType = parsed.productType;
    if(parsed.contentArea) next.filters.contentArea = parsed.contentArea;
    if(parsed.grade) next.filters.grade = parsed.grade;
    if(parsed.demographic) next.filters.demographic = parsed.demographic;
    if(parsed.size) next.filters.size = parsed.size;
    if(parsed.sort) next.filters.sort = parsed.sort;
    if(parsed.productSearch) next.filters.productSearch = parsed.productSearch;
    if(parsed.states.length) {
      next.filters.states = parsed.states;
      next.selectedState = parsed.states[0];
    }
    next.queryAssumptions = parsed.assumptions;
    next.queryLimit = parsed.limit;
    next.querySummary = parsed.summaryParts.length
      ? `NLP interpretation: ${parsed.summaryParts.join(" • ")}`
      : "NLP interpretation: using your manual filters and default rules.";
    const preview = getResults(next).results;
    if(preview.length) next.selectedDistrictId = preview[0].id;
    return normalizeState(next);
  }
  function clearState(){
    return defaultState();
  }
  function selectedDistrict(appState){
    const state = normalizeState(appState);
    const { results, matched } = getResults(state);
    return results.find(d => d.id === state.selectedDistrictId) ||
      matched.find(d => d.id === state.selectedDistrictId) ||
      results[0] || matched[0] || data.districts[0] || null;
  }
  function selectedStateName(appState){
    const state = normalizeState(appState);
    const district = selectedDistrict(state);
    return state.selectedState || state.filters.states[0] || district?.state || allStates[0];
  }
  function exportResults(appState){
    const { filters, results } = getResults(appState);
    if(!results.length){
      window.alert("No results to export.");
      return;
    }
    const activeSubject = filters.contentArea === "All" ? "Math" : filters.contentArea;
    const activeGrade = filters.grade === "All" ? "3" : filters.grade;
    const rows = results.map(d => ({
      district: d.district,
      state: d.state,
      lea_id: d.leaId,
      nces_id: d.ncesId,
      size: d.size,
      enrollment: d.enrollment,
      multilingual_count: d.multilingualCount,
      multilingual_pct: d.multilingualPct,
      white_pct: d.whitePct,
      black_pct: d.blackPct,
      hispanic_pct: d.hispanicPct,
      frl_pct: d.frlPct,
      school_years: d.marketYears.join("; "),
      scoped_subject: activeSubject,
      scoped_grade: activeGrade,
      current_core: getCurrentProduct(d, activeSubject, activeGrade).name,
      supplemental: d.supplemental[activeSubject],
      change_signal: Math.round(getChangeLikelihood(d, activeSubject, activeGrade) * 100),
      hqim_in_scope: getCurrentProduct(d, activeSubject, activeGrade).hqim ? "Yes" : "No",
      board_docs: d.assets.boardDocs.length,
      strategic_plans: d.assets.stratPlans.length
    }));
    const headers = Object.keys(rows[0]);
    const csv = [
      headers.join(","),
      ...rows.map(row => headers.map(key => {
        const value = String(row[key] ?? "");
        const escaped = value.replaceAll('"','""');
        return /[,\n"]/.test(escaped) ? `"${escaped}"` : escaped;
      }).join(","))
    ].join("\n");
    const blob = new Blob([csv], {type:"text/csv;charset=utf-8"});
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = "curriculum_intelligence_results.csv";
    link.click();
    URL.revokeObjectURL(url);
  }
